// src/App.js
import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import MarketplaceHome from './components/MarketplaceHome';
import Register from './components/Register';
import BookingPanel from './components/BookingPanel';

function App() {
  const [token, setToken] = useState(localStorage.getItem('token') || '');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setToken('');
    window.location.href = '/';
  };

  return (
    <Router>
      <div style={{ fontFamily: 'Segoe UI, sans-serif', margin: '0 auto', maxWidth: '1200px', padding: '20px', color: '#333' }}>
        <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '2px solid #0288d1', paddingBottom: '15px' }}>
          <h2 style={{ margin: 0, color: '#0288d1' }}>🏫 Campus Side-Hustle Hub</h2>
          <nav>
            <Link to="/" style={{ marginRight: '15px', textDecoration: 'none', color: '#555', fontWeight: 'bold' }}>Marketplace</Link>
            {!token ? (
              <Link to="/register" style={{ textDecoration: 'none', background: '#0288d1', color: 'white', padding: '8px 16px', borderRadius: '4px' }}>Verify & Register</Link>
            ) : (
              <button onClick={handleLogout} style={{ background: '#d32f2f', color: 'white', border: 'none', padding: '8px 16px', borderRadius: '4px', cursor: 'pointer' }}>Logout</button>
            )}
          </nav>
        </header>

        <main style={{ marginTop: '30px' }}>
          <Routes>
            <Route path="/" element={<MarketplaceHome token={token} />} />
            <Route path="/register" element={<Register setToken={setToken} />} />
            <Route path="/booking/:listingId" element={<BookingPanel token={token} />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
}

export default App;
